export async function authPostData(state) {
  const { nickName, email, password } = state;
  const data = {
    nickName: nickName,
    email: email,
    password: password,
  };
  const propertyPost = {
    method: "POST",
    headers: { Accept: "application/json", "Content-Type": "application/json" },
    body: JSON.stringify(data),
    credentials: "include",
  };
  if (email === "" || password === "") {
    return console.log("Поля должны быть заполнены");
  }
  try {
    const response = await fetch(
      "http://localhost:5000/api/login",
      propertyPost
    );
    const user = await response.json();
    if (user.message === undefined) {
      localStorage.setItem("UserData", JSON.stringify(user.userData));
      return console.log("Операция прошла успешно");
    } else {
      return console.log(user.message.errors[0]["msg"]);
    }
  } catch (error) {
    console.log(error);
  }
}
